fun observeJobs(): Flow<List<Job>> = repository.observeJobs()
    .map { items -> items.filter(Job::isVisible) }
    .distinctUntilChanged()

viewModelScope.launch {
    observeJobs().collect { jobs -> _uiState.value = UiState.Content(jobs) }
}

val uiState: StateFlow<SearchUiState> = query
    .debounce(300)
    .map(String::trim)
    .distinctUntilChanged()
    .flatMapLatest { keyword ->
        flow { emit(SearchUiState.Content(repository.search(keyword))) }
            .onStart { emit(SearchUiState.Loading) }
            .catch { e -> if (e is CancellationException) throw e else emit(SearchUiState.Error(e)) }
    }
    .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), SearchUiState.Idle)
